# Server Implementation
class AuthenticationService:
    def __init__(self):
        self.secret_key = 'your-secret-key-change-in-production'
        self.users = {
            'admin': hashlib.sha256('admin123'.encode()).hexdigest(),
            'user1': hashlib.sha256('password1'.encode()).hexdigest(),
            'user2': hashlib.sha256('password2'.encode()).hexdigest(),
        }

    def Login(self, request, context):
        username = request.username
        password = request.password
        password_hash = hashlib.sha256(password.encode()).hexdigest()

        if username in self.users and self.users[username] == password_hash:
            token = jwt.encode(
                {
                    'username': username,
                    'exp': datetime.utcnow() + timedelta(hours=24)
                },
                self.secret_key,
                algorithm='HS256'
            )
            return LoginResponse(
                success=True,
                token=token,
                message='Login successful'
            )
        else:
            return LoginResponse(
                success=False,
                token='',
                message='Invalid username or password'
            )

    def ValidateToken(self, request, context):
        try:
            payload = jwt.decode(
                request.token,
                self.secret_key,
                algorithms=['HS256']
            )
            return ValidateTokenResponse(
                valid=True,
                username=payload['username']
            )
        except jwt.ExpiredSignatureError:
            return ValidateTokenResponse(valid=False, username='')
        except jwt.InvalidTokenError:
            return ValidateTokenResponse(valid=False, username='')

class DataService:
    def __init__(self, auth_service):
        self.auth_service = auth_service
        self.user_database = {
            'user1': UserData(
                user_id='1',
                username='user1',
                email='user1@example.com',
                created_at='2024-01-01'
            ),
            'user2': UserData(
                user_id='2',
                username='user2',
                email='user2@example.com',
                created_at='2024-01-02'
            ),
            'admin': UserData(
                user_id='3',
                username='admin',
                email='admin@example.com',
                created_at='2024-01-03'
            ),
        }

    def _validate_token(self, token):
        validate_request = ValidateTokenRequest(token=token)
        response = self.auth_service.ValidateToken(validate_request, None)
        return response.valid, response.username

    def GetUserData(self, request, context):
        valid, username = self._validate_token(request.token)
        
        if not valid:
            return GetUserDataResponse(
                success=False,
                message='Invalid or expired token'
            )

        user_id = request.user_id
        user_data = None
        
        for uid, data in self.user_database.items():
            if data.user_id == user_id:
                user_data = data
                break

        if user_data:
            return GetUserDataResponse(
                success=True,
                user_data=user_data,
                message='User data retrieved successfully'
            )
        else:
            return GetUserDataResponse(
                success=False,
                message='User not found'
            )

    def ListUsers(self, request, context):
        valid, username = self._validate_token(request.token)
        
        if not valid:
            return ListUsersResponse(
                success=False,
                message='Invalid or expired token'
            )

        all_users = list(self.user_database.values())
        page = request.page if request.page > 0 else 1
        page_size = request.page_size if request.page_size > 0 else 10
        
        start_idx = (page - 1) * page_size
        end_idx = start_idx + page_size
        
        paginated_users = all_users[start_idx:end_idx]

        return ListUsersResponse(
            success=True,
            users=paginated_users,
            total_count=len(all_users),
            message='Users retrieved successfully'
        )

